'use strict';
class TurnstileGuard{
#form;
#submit;
#widget;
#widgetId=null;#verified=false;#timerId=null;#timedOut=false;#errorRetried=false;
constructor(form,submit,widget){
this.#form=form;
this.#submit=submit;
this.#widget=widget;
const jsFlag=document.createElement('input');
jsFlag.type='hidden';
jsFlag.name='js_enabled';
jsFlag.value='1';
this.#form.appendChild(jsFlag);
this.#submit.disabled=true;
this.#submit.setAttribute('aria-busy','true');
this.#render();
this.#timerId=setTimeout(()=>{
if(!this.#verified){
this.#timedOut=true;
this.#enable();}},5000);}
static#counter=0;
static#instances=[];
static#guardedWidgets=new WeakSet();
static init(){
if(typeof turnstile==='undefined')return TurnstileGuard.#instances;
const widgets=document.querySelectorAll('.cf-turnstile');
for(const widget of widgets){
if(TurnstileGuard.#guardedWidgets.has(widget))continue;
const form=widget.closest('form');
if(!form)continue;
const submit=form.querySelector('[type="submit"]');
if(!submit)continue;
TurnstileGuard.#guardedWidgets.add(widget);
TurnstileGuard.#instances.push(new TurnstileGuard(form,submit,widget));}
return TurnstileGuard.#instances;}#render(){
const sitekey=this.#widget.dataset.sitekey??'';
const action=this.#widget.dataset.action??'';
this.#widgetId=turnstile.render(this.#widget,{
sitekey,
action,
callback:this.#handleVerify,'expired-callback':this.#handleExpire,'error-callback':this.#handleError,
appearance:'interaction-only',
theme:'light',
retry:'auto',
language:'auto',});}#enable(){
this.#submit.disabled=false;
this.#submit.removeAttribute('aria-busy');}#disable(){
this.#submit.disabled=true;
this.#submit.setAttribute('aria-busy','true');}#handleVerify=()=>{
this.#verified=true;
this.#timedOut=false;
this.#errorRetried=false;
clearTimeout(this.#timerId);
this.#enable();};#handleExpire=()=>{
this.#verified=false;
if(!this.#timedOut){
this.#disable();}
if(this.#widgetId!==null){
turnstile.reset(this.#widgetId);}};#handleError=()=>{
clearTimeout(this.#timerId);
if(!this.#errorRetried&&this.#widgetId!==null){
this.#errorRetried=true;
turnstile.reset(this.#widgetId);
return;}
this.#enable();};}
TurnstileGuard.init();